targets.expr:
sum(
  rate(
    k6_chronos_messages_published_total{job="k6-chronos"}[$__rate_interval]
  )
) by (chronos_path) / on() group_left() sum(
  rate(
    k6_chronos_messages_published_total{job="k6-chronos"}[$__rate_interval]
  )
)

histogram_quantile(0.99,
  sum(
    rate(
      k6_kafka_writer_write_seconds_milliseconds_bucket{job="k6-chronos"}[$__rate_interval]
    )
  ) by (le, scenario, topic)
)

sum(
  increase(
    k6_dropped_iterations_total{}[$__rate_interval]
  )
) by (scenario) / sum(
  increase(
    k6_iterations_total[$__rate_interval]
    )
  ) by (scenario)

sum(
  container_memory_usage_bytes{id!="/"}
) by (image) / on() group_left() sum(
  machine_memory_bytes{}
)
